const items = $input.all();
const combined = items
  .map(item => item.json.output || item.json.text || '')
  .filter(t => t.length > 0)
  .join('\n\n');

return [{ json: { output: combined } }];

const items = $input.all();

let stage1Raw = '';
let stage2Raw = '';
let cofounderRaw = '';

// Collect all string values from all items
const allStrings = [];
items.forEach(item => {
  Object.values(item.json).forEach(val => {
    if (typeof val === 'string' && val.length > 30) allStrings.push(val);
  });
});

// Classify each string
for (const val of allStrings) {
  const v = val.toLowerCase();
  const hasCofounder = v.includes('co-founder analysis') || v.includes('co-founder match 1') || v.includes('cofounder match');
  const hasStage2 = v.includes('stage 2 report') || v.includes('section 1') || v.includes('business model canvas') || v.includes('validation scorecard');
  const hasStage1 = v.includes('stage 1 report') || (v.includes('market research') && v.includes('market sizing')) || (v.includes('market landscape') && v.includes('strategic fit'));

  if (hasCofounder && !cofounderRaw) { cofounderRaw = val; }
  else if (hasStage2 && !stage2Raw) { stage2Raw = val; }
  else if (hasStage1 && !stage1Raw) { stage1Raw = val; }
}

// If stage2Raw not found separately, try to split from a combined output
if (!stage2Raw && stage1Raw) {
  const s2idx = stage1Raw.search(/STAGE 2 REPORT/i);
  if (s2idx > 0) {
    stage2Raw = stage1Raw.slice(s2idx);
    stage1Raw = stage1Raw.slice(0, s2idx).trim();
  }
}

// If still nothing, try the combined output field
if (!stage1Raw && !stage2Raw) {
  const combined = items.map(i => i.json.output || i.json.text || '').filter(Boolean).join('\n\n');
  const s2idx = combined.search(/STAGE 2 REPORT/i);
  if (s2idx > 0) {
    stage1Raw = combined.slice(0, s2idx).trim();
    stage2Raw = combined.slice(s2idx).trim();
  } else {
    stage1Raw = combined;
  }
}

function cleanMarkdown(text) {
  if (!text) return '';
  return text
    .replace(/\*\*(.+?)\*\*/gs, '$1')
    .replace(/\*(.+?)\*/gs, '$1')
    .replace(/#{1,6}\s+/g, '')
    .replace(/`{1,3}[^`]*`{1,3}/g, '')
    .replace(/^\s*[-*]\s+/gm, '- ')
    .trim();
}

stage1Raw    = cleanMarkdown(stage1Raw);
stage2Raw    = cleanMarkdown(stage2Raw);
cofounderRaw = cleanMarkdown(cofounderRaw);

function extract(text, froms, tos) {
  if (!text) return '';
  if (typeof froms === 'string') froms = [froms];
  const lo = text.toLowerCase();
  let s = -1, ml = 0;
  for (const f of froms) {
    const i = lo.indexOf(f.toLowerCase());
    if (i !== -1 && (s === -1 || i < s)) { s = i; ml = f.length; }
  }
  if (s === -1) return '';
  let e = text.length;
  (tos || []).forEach(t => {
    const i = lo.indexOf(t.toLowerCase(), s + ml);
    if (i !== -1 && i < e) e = i;
  });
  return text.slice(s + ml, e).trim();
}

// Extract sections from stage2 - try multiple header variants
const bmcMarkers   = ['section 1 \u2014 business model canvas', 'section 1 - business model canvas', 'business model canvas\n'];
const valMarkers   = ['section 2 \u2014 validation scorecard', 'section 2 - validation scorecard', 'validation scorecard\n'];
const sugMarkers   = ['section 3 \u2014 improvement suggestions', 'section 3 - improvement suggestions', 'improvement suggestions\n'];
const bmcEnd       = ['section 2', 'validation scorecard'];
const valEnd       = ['section 3', 'improvement suggestions'];
const sugEnd       = ['verdict:', 'stop here'];

const bmc        = cleanMarkdown(extract(stage2Raw, bmcMarkers, bmcEnd));
const validation = cleanMarkdown(extract(stage2Raw, valMarkers, valEnd));
const suggestions= cleanMarkdown(extract(stage2Raw, sugMarkers, sugEnd));

// Fallback: if sections still empty, use the full stage2Raw for each
const verdictMatch = stage2Raw.match(/verdict[:\s]+([^\n]+)/i);
const reasonMatch  = stage2Raw.match(/reason[:\s]+([^\n]+)/i);

return [{
  json: {
    output: stage1Raw + '\n\n' + stage2Raw + '\n\n' + cofounderRaw,
    stage1: stage1Raw,
    stage2: stage2Raw,
    bmc: bmc || '',
    validation: validation || '',
    suggestions: suggestions || '',
    cofounder: cofounderRaw || '',
    verdict: verdictMatch ? verdictMatch[1].trim() : '',
    reason: reasonMatch ? reasonMatch[1].trim() : '',
  }
}];

const raw = $input.first().json.output || $input.first().json.text || '';
let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : {};
} catch(e) {
  parsed = { score: 5, status: 'PASS', reason: 'Could not parse score', questions: [] };
}

const score = parsed.score || 5;
const status = parsed.status || (score >= 5 ? 'PASS' : 'FOLLOWUP');

// Get the raw idea from webhook
let rawIdea = $('Main Webhook').first().json.body.idea || '';

// If it's a refined submission, extract just the original idea + answers cleanly
let cleanIdea = rawIdea;
if (rawIdea.includes('REFINED_SUBMISSION:')) {
  // Extract the original idea
  const origMatch = rawIdea.match(/Original idea:\s*([\s\S]+?)$/i);
  // Extract all Q&A answers
  const answerMatches = [...rawIdea.matchAll(/A:\s*([^\n]+)/g)];
  const answers = answerMatches.map(m => m[1].trim()).join('. ');
  // Combine into a clean readable idea
  if (origMatch) {
    cleanIdea = origMatch[1].trim() + ' ' + answers;
  } else {
    cleanIdea = answers;
  }
}

return [{
  json: {
    ...($input.first().json),
    ideaScore: score,
    ideaScoreReason: parsed.reason || '',
    ideaStatus: status,
    followupQuestions: parsed.questions || [],
    founderName: $('Main Webhook').first().json.body.name,
    employeeId: $('Main Webhook').first().json.body.employeeId,
    linkedin: $('Main Webhook').first().json.body.linkedin || '',
    idea: cleanIdea,
  }
}];

const newIdea = ($('Parse Score').first().json.idea || '').toLowerCase();
const founderName = $('Parse Score').first().json.founderName || '';
const employeeId = $('Parse Score').first().json.employeeId || '';
const ideaScore = $('Parse Score').first().json.ideaScore || 0;
const linkedin = $('Parse Score').first().json.linkedin || '';

const allRows = $input.all().map(item => item.json);

function similarity(a, b) {
  const stopwords = new Set(['the','and','for','are','but','not','you','all','can','was','had','our','out','who','get','how','its','use','will','with','that','this','from','they','what','been','have','more','when','also','into','than','then','some','your','just','like','make','many','most','over','such','take','time','very','well','were','even','back','does','done','give','good','know','last','made','need','only','part','same','tell','used','want','ways','work','would','could','their','about','which','there','other','after','first','these','those','where','while','should']);
  const wordsA = new Set(a.split(/\W+/).filter(w => w.length > 3 && !stopwords.has(w)));
  const wordsB = new Set(b.split(/\W+/).filter(w => w.length > 3 && !stopwords.has(w)));
  if (wordsA.size === 0 || wordsB.size === 0) return 0;
  const intersection = [...wordsA].filter(w => wordsB.has(w)).length;
  const union = new Set([...wordsA, ...wordsB]).size;
  return Math.round((intersection / union) * 100);
}

let highestScore = 0;
let matchedRow = null;
const allScores = [];

for (const row of allRows) {
  if (String(row['Employee ID']).trim() === String(employeeId).trim()) continue;
  const existingIdea = (row['Idea Description'] || '').toLowerCase();
  if (!existingIdea) continue;
  const score = similarity(newIdea, existingIdea);
  allScores.push({ name: row['Name'], score });
  if (score > highestScore) {
    highestScore = score;
    matchedRow = row;
  }
}

// LOWER threshold to 40% to catch semantic matches
const THRESHOLD = 40;

return [{
  json: {
    founderName,
    employeeId,
    ideaScore,
    linkedin,
    idea: $('Parse Score').first().json.idea || '',
    followupQuestions: $('Parse Score').first().json.followupQuestions || [],
    similarityScore: highestScore,
    similarityStatus: highestScore >= THRESHOLD ? 'SIMILAR' : 'UNIQUE',
    matchedFounder: matchedRow ? (matchedRow['Name'] || null) : null,
    matchedEmployeeId: matchedRow ? (matchedRow['Employee ID'] || null) : null,
    matchedIdea: matchedRow ? (matchedRow['Idea Description'] || null) : null,
    debugScores: allScores,
  }
}];

const input = $input.first().json;
const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
let id = 'RPT-';
for (let i = 0; i < 6; i++) id += chars[Math.floor(Math.random() * chars.length)];
return [{ json: { ...input, reportId: id, generatedAt: new Date().toISOString() } }];

const item = $('Generate Report ID').first().json;
const reportId = item.reportId || 'RPT-UNKNOWN';
const shareUrl = 'https://n8n.srv1365779.hstgr.cloud/webhook/incubator';
return [{ json: {
  ...item,
  reportId,
  shareUrl,
  stage1: item.stage1 || '',
  stage2: item.stage2 || '',
  bmc: item.bmc || '',
  validation: item.validation || '',
  suggestions: item.suggestions || '',
  cofounder: item.cofounder || '',
  verdict: item.verdict || '',
  reason: item.reason || '',
  output: item.output || ''
} }];

const r = $input.first().json;
if (!r || !r.report_id) {
  return [{ json: { html: '<html><body style="font-family:sans-serif;padding:40px;text-align:center"><h2>Report not found</h2><p>This link may have expired or the report ID is invalid.</p></body></html>' } }];
}
function section(title, content) {
  if (!content || !content.trim()) return '';
  const lines = content.split('\n').map(l => {
    l = l.trim(); if (!l) return '';
    if (l.startsWith('- ')) return `<li>${l.slice(2)}</li>`;
    const colonIdx = l.indexOf(':');
    if (colonIdx > 0 && colonIdx < 40 && l === l.toUpperCase().slice(0, colonIdx) + l.slice(colonIdx))
      return `<p><strong>${l.slice(0,colonIdx)}</strong>: ${l.slice(colonIdx+1).trim()}</p>`;
    return `<p>${l}</p>`;
  }).join('');
  return `<div class="section"><h2>${title}</h2><div class="body">${lines}</div></div>`;
}
const vc = (r.verdict||'').toUpperCase().includes('ADVANCE TO') ? '#16a34a' : (r.verdict||'').toUpperCase().includes('CONDITIONS') ? '#d97706' : '#dc2626';
const dateStr = r.created_at ? new Date(r.created_at).toLocaleDateString('en-GB',{day:'numeric',month:'long',year:'numeric'}) : '';
