const assessment = $('Improvement Agent').first().json.output || '';
const reportId = $('Main Webhook').first().json.body.reportId;
const employeeId = $('Main Webhook').first().json.body.employeeId;

// Extract prototype recommendation
const protoMatch = assessment.match(/Recommended:\s*([^\n]+)/i);
const protoType = protoMatch ? protoMatch[1].trim() : '';

// Extract new score
const newScoreMatch = assessment.match(/New Score:\s*([0-9.]+)/i);
const newScore = newScoreMatch ? newScoreMatch[1].trim() : '';

// Extract delta
const deltaMatch = assessment.match(/Delta:\s*([^\n]+)/i);
const delta = deltaMatch ? deltaMatch[1].trim() : '';

// Extract progress summary
const summaryMatch = assessment.match(/PROGRESS SUMMARY\n([\s\S]+?)(?=\nSCORE|\nISSUES|$)/i);
const summary = summaryMatch ? summaryMatch[1].trim() : '';

return [{ json: {
  reportId,
  employeeId,
  protoType,
  newScore,
  delta,
  summary,
  assessment
}}];

